import React, { useState } from 'react';
import { SkillLevel } from '../types';
import { GOALS, LEVELS, ICONS } from '../constants';

interface DiscoveryPageProps {
  onStart: (skill: string, goal: string, level: SkillLevel) => void;
}

const DiscoveryPage: React.FC<DiscoveryPageProps> = ({ onStart }) => {
  const [skill, setSkill] = useState('');
  const [goal, setGoal] = useState(GOALS[0].id);
  const [level, setLevel] = useState<SkillLevel>(SkillLevel.BEGINNER);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!skill.trim()) return;
    onStart(skill, goal, level);
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[70vh] animate-in fade-in slide-in-from-bottom-4 duration-1000">
      <div className="max-w-2xl w-full text-center space-y-8">
        <h1 className="text-5xl md:text-7xl font-space font-bold tracking-tighter">
          Master Any <span className="text-transparent bg-clip-text bg-gradient-to-r from-sky-400 to-purple-500">Technical Skill</span>
        </h1>
        <p className="text-slate-400 text-lg md:text-xl">
          Enter a domain. Verify your level. Get an AI-architected path to mastery.
        </p>

        <form onSubmit={handleSubmit} className="space-y-6 text-left">
          <div className="glass p-8 rounded-3xl space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-widest text-slate-500 ml-1">What do you want to learn?</label>
              <input 
                type="text" 
                value={skill}
                onChange={(e) => setSkill(e.target.value)}
                placeholder="e.g. Kubernetes, Redis, Rust, LLMs..."
                className="w-full bg-slate-900/50 border border-white/10 rounded-2xl px-6 py-4 text-xl focus:outline-none focus:ring-2 focus:ring-sky-500/50 transition-all placeholder:text-slate-600"
                required
              />
            </div>

            <div className="grid md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-xs font-bold uppercase tracking-widest text-slate-500 ml-1">Current Experience</label>
                <div className="grid grid-cols-2 gap-2">
                  {LEVELS.map((l) => (
                    <button
                      key={l}
                      type="button"
                      onClick={() => setLevel(l as SkillLevel)}
                      className={`px-4 py-3 rounded-xl text-sm font-medium transition-all border ${
                        level === l 
                          ? 'bg-sky-500/10 border-sky-400 text-sky-400' 
                          : 'bg-slate-900/30 border-white/5 text-slate-400 hover:border-white/20'
                      }`}
                    >
                      {l}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold uppercase tracking-widest text-slate-500 ml-1">Primary Goal</label>
                <select 
                  value={goal}
                  onChange={(e) => setGoal(e.target.value)}
                  className="w-full bg-slate-900/30 border border-white/10 rounded-2xl px-6 py-4 text-slate-300 focus:outline-none focus:ring-2 focus:ring-sky-500/50 appearance-none"
                >
                  {GOALS.map((g) => (
                    <option key={g.id} value={g.id} className="bg-slate-900">{g.label}</option>
                  ))}
                </select>
              </div>
            </div>

            <button
              type="submit"
              className="w-full group bg-gradient-to-r from-sky-500 to-indigo-600 hover:from-sky-400 hover:to-indigo-500 text-white font-bold py-5 rounded-2xl flex items-center justify-center gap-3 transition-all shadow-lg hover:shadow-sky-500/20"
            >
              Start Architecture Flow
              <ICONS.ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
            </button>
          </div>
        </form>

        <div className="flex justify-center gap-8 text-slate-500 pt-4">
          <div className="flex items-center gap-2">
            <ICONS.Zap className="w-5 h-5 text-yellow-400" />
            <span>Interactive Labs</span>
          </div>
          <div className="flex items-center gap-2">
            <ICONS.CheckCircle className="w-5 h-5 text-emerald-400" />
            <span>AI Verified Skills</span>
          </div>
          <div className="flex items-center gap-2">
            <ICONS.Trophy className="w-5 h-5 text-sky-400" />
            <span>Adaptive Paths</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DiscoveryPage;

import React, { useState } from 'react';
import { AssessmentQuestion } from '../types';
import { ICONS } from '../constants';

interface AssessmentPageProps {
  skill: string;
  questions: AssessmentQuestion[];
  onComplete: (results: { questionId: string; selectedIndex: number; isCorrect: boolean }[]) => void;
}

const AssessmentPage: React.FC<AssessmentPageProps> = ({ skill, questions, onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [results, setResults] = useState<{ questionId: string; selectedIndex: number; isCorrect: boolean }[]>([]);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);

  const currentQuestion = questions[currentIndex];

  const handleNext = () => {
    if (selectedOption === null) return;

    const isCorrect = selectedOption === currentQuestion.correctIndex;
    const newResults = [...results, { 
      questionId: currentQuestion.id, 
      selectedIndex: selectedOption, 
      isCorrect 
    }];

    if (currentIndex < questions.length - 1) {
      setResults(newResults);
      setCurrentIndex(currentIndex + 1);
      setSelectedOption(null);
    } else {
      onComplete(newResults);
    }
  };

  const progress = ((currentIndex + 1) / questions.length) * 100;

  return (
    <div className="max-w-3xl mx-auto py-10 animate-in fade-in duration-700">
      <div className="flex justify-between items-end mb-8">
        <div>
          <h2 className="text-3xl font-space font-bold mb-1">Skill Verification: <span className="text-sky-400">{skill}</span></h2>
          <p className="text-slate-400">Question {currentIndex + 1} of {questions.length}</p>
        </div>
        <div className="text-right">
          <span className="text-xs font-bold text-sky-400 uppercase tracking-widest">Verification Status</span>
          <div className="flex gap-1 mt-2">
            {questions.map((_, idx) => (
              <div 
                key={idx} 
                className={`w-8 h-1.5 rounded-full transition-all duration-500 ${
                  idx < currentIndex ? 'bg-sky-500' : idx === currentIndex ? 'bg-sky-400 animate-pulse' : 'bg-slate-800'
                }`}
              />
            ))}
          </div>
        </div>
      </div>

      <div className="glass p-10 rounded-3xl relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-slate-800">
          <div 
            className="h-full bg-gradient-to-r from-sky-400 to-indigo-500 transition-all duration-500"
            style={{ width: `${progress}%` }}
          />
        </div>

        <div className="mt-4">
          <span className="inline-block px-3 py-1 bg-sky-500/10 text-sky-400 text-xs font-bold rounded-full mb-4 border border-sky-500/20 uppercase">
            {currentQuestion.category}
          </span>
          <h3 className="text-2xl font-medium leading-relaxed text-slate-100 mb-8">
            {currentQuestion.question}
          </h3>

          <div className="space-y-4">
            {currentQuestion.options.map((option, idx) => (
              <button
                key={idx}
                onClick={() => setSelectedOption(idx)}
                className={`w-full text-left p-6 rounded-2xl border transition-all flex items-center justify-between group ${
                  selectedOption === idx 
                    ? 'bg-sky-500/10 border-sky-500 text-sky-400 ring-2 ring-sky-500/20 shadow-lg' 
                    : 'bg-slate-900/30 border-white/5 text-slate-400 hover:border-white/20 hover:bg-slate-900/50'
                }`}
              >
                <span className="flex-1 text-lg">{option}</span>
                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
                  selectedOption === idx ? 'border-sky-500' : 'border-slate-700 group-hover:border-slate-500'
                }`}>
                  {selectedOption === idx && <div className="w-3 h-3 bg-sky-500 rounded-full" />}
                </div>
              </button>
            ))}
          </div>

          <div className="mt-10 flex justify-end">
            <button
              onClick={handleNext}
              disabled={selectedOption === null}
              className={`px-10 py-4 rounded-2xl font-bold flex items-center gap-2 transition-all ${
                selectedOption === null 
                  ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
                  : 'bg-white text-slate-950 hover:bg-sky-400 shadow-xl shadow-sky-950/20'
              }`}
            >
              {currentIndex === questions.length - 1 ? 'Finalize' : 'Continue'}
              <ICONS.ArrowRight className="w-5 h-5" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AssessmentPage;

import React from 'react';
import { SkillLevel } from '../types';
import { ICONS } from '../constants';

interface ResultPageProps {
  results: { questionId: string; selectedIndex: number; isCorrect: boolean }[];
  initialLevel: SkillLevel;
  verifiedLevel: SkillLevel;
  onProceed: () => void;
}

const ResultPage: React.FC<ResultPageProps> = ({ results, initialLevel, verifiedLevel, onProceed }) => {
  const correctCount = results.filter(r => r.isCorrect).length;
  const isDowngraded = initialLevel !== verifiedLevel;

  return (
    <div className="max-w-4xl mx-auto py-12 animate-in zoom-in duration-500">
      <div className="text-center space-y-4 mb-12">
        <h2 className="text-4xl md:text-5xl font-space font-bold">Assessment Complete</h2>
        <p className="text-slate-400 text-xl">We've analyzed your responses to calculate your starting point.</p>
      </div>

      <div className="grid md:grid-cols-2 gap-8 mb-12">
        <div className="glass p-8 rounded-3xl border-sky-500/20 relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4">
            <ICONS.Zap className="w-12 h-12 text-sky-500/20 group-hover:scale-110 transition-transform" />
          </div>
          <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Verification Score</h3>
          <div className="flex items-baseline gap-2">
            <span className="text-7xl font-space font-bold text-sky-400">{correctCount}</span>
            <span className="text-3xl font-space font-bold text-slate-600">/ {results.length}</span>
          </div>
          <p className="mt-4 text-slate-300">
            {correctCount >= 4 
              ? "Impressive! You have a solid foundational understanding of the core concepts." 
              : "There are some gaps in the conceptual framework that we'll address in the roadmap."}
          </p>
        </div>

        <div className="glass p-8 rounded-3xl border-purple-500/20 relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4">
            <ICONS.Trophy className="w-12 h-12 text-purple-500/20 group-hover:scale-110 transition-transform" />
          </div>
          <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Calculated Skill Level</h3>
          <div className="flex items-center gap-4">
            <span className={`text-5xl font-space font-bold ${isDowngraded ? 'text-amber-400' : 'text-purple-400'}`}>
              {verifiedLevel}
            </span>
          </div>
          {isDowngraded ? (
            <p className="mt-4 text-slate-300">
              We've adjusted your starting level to <span className="text-amber-400 font-bold">{verifiedLevel}</span> based on specific conceptual misses. This will ensure your foundations are rock-solid.
            </p>
          ) : (
            <p className="mt-4 text-slate-300">
              Your self-assessment matches your verified performance. We will build a path starting from <span className="text-purple-400 font-bold">{verifiedLevel}</span>.
            </p>
          )}
        </div>
      </div>

      <div className="flex flex-col items-center gap-6">
        <button
          onClick={onProceed}
          className="px-12 py-5 rounded-2xl bg-gradient-to-r from-sky-500 to-indigo-600 hover:scale-105 transition-all text-white font-bold text-xl shadow-xl shadow-sky-500/20 flex items-center gap-3"
        >
          Generate My Personalized Roadmap
          <ICONS.ArrowRight className="w-6 h-6" />
        </button>
        <p className="text-slate-500 text-sm">Takes about 10-15 seconds to architect your path</p>
      </div>
    </div>
  );
};

export default ResultPage;

import React from 'react';
import { LearningRoadmap } from '../types';
import { ICONS } from '../constants';

interface RoadmapPageProps {
  roadmap: LearningRoadmap;
