import { GoogleGenAI, Type } from "@google/genai";
import { SkillLevel, AssessmentQuestion, LearningRoadmap } from "../types";

const API_KEY = process.env.API_KEY || '';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY });
  }

  async generateAssessment(skill: string, level: SkillLevel): Promise<AssessmentQuestion[]> {
    const prompt = `Generate a set of 5 interactive, high-quality technical assessment questions for the skill "${skill}" at a ${level} level. 
    Focus on practical, scenario-based understanding rather than raw syntax. 
    Ensure one or two questions push the boundaries of the selected level to accurately verify competence.
    Avoid long typing-heavy answers, keep options clear and conceptual.`;

    const response = await this.ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              question: { type: Type.STRING },
              options: { 
                type: Type.ARRAY, 
                items: { type: Type.STRING } 
              },
              correctIndex: { type: Type.INTEGER },
              explanation: { type: Type.STRING },
              category: { type: Type.STRING }
            },
            required: ["id", "question", "options", "correctIndex", "explanation", "category"]
          }
        }
      }
    });

    try {
      const data = JSON.parse(response.text);
      return Array.isArray(data) ? data : [];
    } catch (e) {
      console.error("Failed to parse assessment response", e);
      return [];
    }
  }

  async generateRoadmap(skill: string, level: SkillLevel, duration: number, goal: string): Promise<LearningRoadmap> {
    const isNoIdea = level === SkillLevel.NO_IDEA;

    const prompt = `Act as an expert Learning Architect. Generate a ${duration}-day personalized, adaptive technical roadmap for learning "${skill}".
    The learner's current level is: ${level}.
    The learner's goal is: "${goal}".

    ${isNoIdea ? `
    CRITICAL INSTRUCTION for "No Idea / Just Start" level:
    - Zero-assumption content: Start from the very basics.
    - Focus on mental models and visual metaphors.
    - Avoid technical jargon in the first 2 days, or explain it immediately.
    - Include high-confidence building tasks.
    ` : `
    Adaptive instructions for ${level}:
    - Skip fundamentals that are beneath this level.
    - Focus on advanced patterns, performance, and real-world edge cases.
    `}

    Structure the roadmap day-by-day. For each day, include:
    - Concept: Clear, punchy learning objective.
    - Relevance: Why this matters in the real world (e.g. production scenarios).
    - Hands-on task: A practical mini-project or exercise.
    - Quiz questions: 2-3 interactive conceptual questions (Progressive disclosure style: Question -> Guess -> Explain).
    - Challenge: A "stretch" goal for the day.
    - Estimated time: Total hours for the day.

    Use a conversational, encouraging, yet technically precise tone. Avoid long paragraphs. Use bullet points for tasks.`;

    const response = await this.ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            skill: { type: Type.STRING },
            level: { type: Type.STRING },
            duration: { type: Type.INTEGER },
            goal: { type: Type.STRING },
            days: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  day: { type: Type.INTEGER },
                  concept: { type: Type.STRING },
                  relevance: { type: Type.STRING },
                  handsOnTask: { type: Type.STRING },
                  estimatedTime: { type: Type.STRING },
                  quizQuestions: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        question: { type: Type.STRING },
                        options: { type: Type.ARRAY, items: { type: Type.STRING } },
                        answer: { type: Type.STRING }
                      },
                      required: ["question", "options", "answer"]
                    }
                  },
                  challenge: { type: Type.STRING }
                },
                required: ["day", "concept", "relevance", "handsOnTask", "estimatedTime", "quizQuestions", "challenge"]
              }
            }
          },
          required: ["skill", "level", "duration", "goal", "days"]
        }
      }
    });

    try {
      return JSON.parse(response.text);
    } catch (e) {
      console.error("Failed to parse roadmap response", e);
      throw e;
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useEffect, useCallback } from 'react';
import { AppState, SkillLevel, AssessmentQuestion, LearningRoadmap } from './types';
import { GOALS, ICONS } from './constants';
import { geminiService } from './services/gemini';

// Components
import DiscoveryPage from './pages/DiscoveryPage';
import AssessmentPage from './pages/AssessmentPage';
import ResultPage from './pages/ResultPage';
import RoadmapPage from './pages/RoadmapPage';
import DashboardPage from './pages/DashboardPage';
import SessionPage from './pages/SessionPage';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    currentStep: 'discovery',
    skillName: '',
    selectedGoal: GOALS[0].id,
    initialLevel: SkillLevel.BEGINNER,
    verifiedLevel: null,
    assessmentQuestions: [],
    assessmentResults: [],
    roadmap: null,
    activeDay: 1,
    streak: 3,
    confidenceScore: 0,
  });

  const [loading, setLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState('');

  const handleStartDiscovery = async (skill: string, goal: string, level: SkillLevel) => {
    setState(prev => ({
      ...prev,
      skillName: skill,
      selectedGoal: goal,
      initialLevel: level,
    }));

    if (level === SkillLevel.NO_IDEA) {
      // Skip assessment for NO_IDEA users
      await generateRoadmapInternal(skill, level, goal);
    } else {
      setLoading(true);
      setLoadingMsg('Architecting your assessment...');
      try {
        const questions = await geminiService.generateAssessment(skill, level);
        setState(prev => ({
          ...prev,
          assessmentQuestions: questions,
          currentStep: 'assessment',
        }));
      } catch (error) {
        console.error(error);
        alert('Failed to generate assessment. Please try again.');
      } finally {
        setLoading(false);
      }
    }
  };

  const handleAssessmentComplete = (results: { questionId: string; selectedIndex: number; isCorrect: boolean }[]) => {
    const correctCount = results.filter(r => r.isCorrect).length;
    let verified = state.initialLevel;

    // Simple downgrade logic: if < 60% correct, downgrade.
    if (correctCount < 3) {
      const levels = [
        SkillLevel.BEGINNER,
        SkillLevel.INTERMEDIATE,
        SkillLevel.ADVANCED,
        SkillLevel.EXPERT
      ];
      const currentIndex = levels.indexOf(state.initialLevel);
      if (currentIndex > 0) {
        verified = levels[currentIndex - 1];
      } else {
        verified = SkillLevel.NO_IDEA;
      }
    }

    setState(prev => ({
      ...prev,
      assessmentResults: results,
      verifiedLevel: verified,
      currentStep: 'result'
    }));
  };

  const generateRoadmapInternal = async (skill: string, level: SkillLevel, goal: string) => {
    setLoading(true);
    setLoadingMsg('Personalizing your zero-assumption path...');
    try {
      const duration = goal === 'interview' ? 14 : 30;
      const roadmap = await geminiService.generateRoadmap(
        skill,
        level,
        duration,
        goal
      );
      setState(prev => ({
        ...prev,
        roadmap,
        currentStep: 'roadmap'
      }));
    } catch (error) {
      console.error(error);
      alert('Failed to generate roadmap.');
    } finally {
      setLoading(false);
    }
  };

  const handleGenerateRoadmap = async () => {
    await generateRoadmapInternal(state.skillName, state.verifiedLevel || state.initialLevel, state.selectedGoal);
  };

  const navigateTo = (step: AppState['currentStep'], payload?: Partial<AppState>) => {
    setState(prev => ({ ...prev, currentStep: step, ...payload }));
  };

  return (
    <div className="min-h-screen relative overflow-hidden flex flex-col">
      {/* Background Decor */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-sky-500/10 blur-[120px] rounded-full"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-500/10 blur-[120px] rounded-full"></div>

      {/* Navigation Header */}
      <nav className="z-50 px-6 py-4 flex justify-between items-center border-b border-white/5 bg-slate-950/50 backdrop-blur-md sticky top-0">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => navigateTo('discovery')}>
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-sky-400 to-purple-600 flex items-center justify-center neon-blue">
            <ICONS.Brain className="w-6 h-6 text-white" />
          </div>
          <span className="font-space text-xl font-bold tracking-tight">NEXUS<span className="text-sky-400">.</span>ACADEMY</span>
        </div>

        {state.currentStep !== 'discovery' && (
          <div className="flex gap-4 items-center">
            <div className="hidden md:flex flex-col items-end">
              <span className="text-xs text-slate-400 uppercase tracking-widest font-bold">Progress</span>
              <div className="w-32 h-1 bg-slate-800 rounded-full overflow-hidden mt-1">
                <div className="h-full bg-sky-400 w-1/4"></div>
              </div>
            </div>
            <button 
              onClick={() => navigateTo('dashboard')}
              className="px-4 py-2 rounded-lg glass hover:bg-white/10 transition-colors"
            >
              Dashboard
            </button>
          </div>
        )}
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 z-10 p-6 max-w-7xl mx-auto w-full">
        {loading ? (
          <div className="flex flex-col items-center justify-center h-full gap-6">
            <div className="relative">
              <div className="w-24 h-24 border-4 border-sky-400/20 border-t-sky-400 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <ICONS.Brain className="w-8 h-8 text-sky-400 animate-pulse" />
              </div>
            </div>
            <p className="text-xl font-space text-slate-300 animate-pulse-soft">{loadingMsg}</p>
          </div>
        ) : (
          <>
            {state.currentStep === 'discovery' && (
              <DiscoveryPage onStart={handleStartDiscovery} />
            )}
            {state.currentStep === 'assessment' && (
              <AssessmentPage 
                questions={state.assessmentQuestions} 
                onComplete={handleAssessmentComplete}
                skill={state.skillName}
              />
            )}
            {state.currentStep === 'result' && (
              <ResultPage 
                results={state.assessmentResults} 
                initialLevel={state.initialLevel}
                verifiedLevel={state.verifiedLevel!}
                onProceed={handleGenerateRoadmap}
              />
            )}
            {state.currentStep === 'roadmap' && (
              <RoadmapPage 
                roadmap={state.roadmap!} 
                onSelectDay={(day) => setState(prev => ({ ...prev, activeDay: day, currentStep: 'session' }))}
              />
            )}
            {state.currentStep === 'session' && (
              <SessionPage 
                day={state.roadmap!.days.find(d => d.day === state.activeDay)!}
                onComplete={() => navigateTo('dashboard')}
              />
            )}
            {state.currentStep === 'dashboard' && (
              <DashboardPage state={state} />
            )}
          </>
        )}
      </main>

      <footer className="z-10 py-6 border-t border-white/5 text-center text-slate-500 text-sm">
        <p>© 2024 Nexus Academy. Futuristic AI Learning.</p>
      </footer>
    </div>
  );
};

