import { GoogleGenAI, Type, Chat, GenerateContentResponse } from "@google/genai";
import { SkillLevel, AssessmentQuestion, LearningRoadmap, ChatMessage } from "../types";

const API_KEY = process.env.API_KEY || '';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY });
  }

  async generateAssessment(skill: string, level: SkillLevel): Promise<AssessmentQuestion[]> {
    const prompt = `Generate a set of 5 interactive, high-quality technical assessment questions for the skill "${skill}" at a ${level} level. 
    Focus on practical, scenario-based understanding rather than raw syntax. 
    Ensure one or two questions push the boundaries of the selected level to accurately verify competence.
    Avoid long typing-heavy answers, keep options clear and conceptual.`;

    const response = await this.ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              question: { type: Type.STRING },
              options: { 
                type: Type.ARRAY, 
                items: { type: Type.STRING } 
              },
              correctIndex: { type: Type.INTEGER },
              explanation: { type: Type.STRING },
              category: { type: Type.STRING }
            },
            required: ["id", "question", "options", "correctIndex", "explanation", "category"]
          }
        }
      }
    });

    try {
      const data = JSON.parse(response.text);
      return Array.isArray(data) ? data : [];
    } catch (e) {
      console.error("Failed to parse assessment response", e);
      return [];
    }
  }

  async generateRoadmap(skill: string, level: SkillLevel, duration: number, goal: string): Promise<LearningRoadmap> {
    const isNoIdea = level === SkillLevel.NO_IDEA;

    const prompt = `Act as an expert Learning Architect. Generate a ${duration}-day personalized, adaptive technical roadmap for learning "${skill}".
    The learner's current level is: ${level}.
    The learner's goal is: "${goal}".

    ${isNoIdea ? `
    CRITICAL INSTRUCTION for "No Idea / Just Start" level:
    - Zero-assumption content: Start from the very basics.
    - Focus on mental models and visual metaphors.
    - Avoid technical jargon in the first 2 days, or explain it immediately.
    - Include high-confidence building tasks.
    ` : `
    Adaptive instructions for ${level}:
    - Skip fundamentals that are beneath this level.
    - Focus on advanced patterns, performance, and real-world edge cases.
    `}

    Structure the roadmap day-by-day. For each day, include:
    - Concept: Clear, punchy learning objective.
    - Relevance: Why this matters in the real world (e.g. production scenarios).
    - Hands-on task: A practical mini-project or exercise.
    - Quiz questions: 2-3 interactive conceptual questions (Progressive disclosure style: Question -> Guess -> Explain).
    - Challenge: A "stretch" goal for the day.
    - Estimated time: Total hours for the day.

    Use a conversational, encouraging, yet technically precise tone. Avoid long paragraphs. Use bullet points for tasks.`;

    const response = await this.ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            skill: { type: Type.STRING },
            level: { type: Type.STRING },
            duration: { type: Type.INTEGER },
            goal: { type: Type.STRING },
            days: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  day: { type: Type.INTEGER },
                  concept: { type: Type.STRING },
                  relevance: { type: Type.STRING },
                  handsOnTask: { type: Type.STRING },
                  estimatedTime: { type: Type.STRING },
                  quizQuestions: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        question: { type: Type.STRING },
                        options: { type: Type.ARRAY, items: { type: Type.STRING } },
                        answer: { type: Type.STRING }
                      },
                      required: ["question", "options", "answer"]
                    }
                  },
                  challenge: { type: Type.STRING }
                },
                required: ["day", "concept", "relevance", "handsOnTask", "estimatedTime", "quizQuestions", "challenge"]
              }
            }
          },
          required: ["skill", "level", "duration", "goal", "days"]
        }
      }
    });

    try {
      return JSON.parse(response.text);
    } catch (e) {
      console.error("Failed to parse roadmap response", e);
      throw e;
    }
  }

  createMentorChat(skill: string, level: SkillLevel, goal: string): Chat {
    return this.ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are an expert AI Mentor in ${skill}. 
        The student is at ${level} level with the goal of ${goal}.
        Your tone is futuristic, supportive, and technically brilliant.
        Always provide code examples or visual metaphors when explaining.
        Keep responses concise and interaction-heavy. Encourage the student to 'try' things.`
      }
    });
  }
}

export const geminiService = new GeminiService();

import React, { useState, useRef, useEffect } from 'react';
import { AppState, ChatMessage } from '../types';
import { ICONS } from '../constants';
import { geminiService } from '../services/gemini';
import { Chat, GenerateContentResponse } from '@google/genai';

interface MentorPageProps {
  state: AppState;
  updateChatHistory: (messages: ChatMessage[]) => void;
}

const MentorPage: React.FC<MentorPageProps> = ({ state, updateChatHistory }) => {
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const chatRef = useRef<Chat | null>(null);

  useEffect(() => {
    if (!chatRef.current) {
      chatRef.current = geminiService.createMentorChat(state.skillName, state.verifiedLevel || state.initialLevel, state.selectedGoal);
    }
  }, [state]);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [state.chatHistory]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMessage: ChatMessage = { role: 'user', text: input };
    const updatedHistory = [...state.chatHistory, userMessage];
    updateChatHistory(updatedHistory);
    setInput('');
    setIsTyping(true);

    try {
      if (chatRef.current) {
        const stream = await chatRef.current.sendMessageStream({ message: input });
        let modelText = '';

        // Optimistically add empty model message
        const finalHistory = [...updatedHistory, { role: 'model', text: '' } as ChatMessage];

        for await (const chunk of stream) {
          const c = chunk as GenerateContentResponse;
          modelText += c.text;
          const currentHistory = [...updatedHistory, { role: 'model', text: modelText }];
          updateChatHistory(currentHistory);
        }
      }
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = { role: 'model', text: "Apologies, neural sync lost. Please retry link." };
      updateChatHistory([...updatedHistory, errorMsg]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[75vh] animate-in fade-in duration-700">
      <div className="flex items-center justify-between mb-6 px-4">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-2xl bg-sky-500/10 border border-sky-500/20 flex items-center justify-center">
            <ICONS.Brain className="w-6 h-6 text-sky-400" />
          </div>
          <div>
            <h2 className="text-2xl font-space font-bold">Neural Mentor</h2>
            <p className="text-xs text-slate-500 font-bold uppercase tracking-widest flex items-center gap-1">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
              Synchronized: {state.skillName}
            </p>
          </div>
        </div>
      </div>

      <div className="flex-1 glass rounded-[2.5rem] overflow-hidden flex flex-col relative">
        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto p-8 space-y-6 scrollbar-hide"
        >
          {state.chatHistory.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-4 opacity-50">
              <ICONS.Message className="w-12 h-12 text-slate-600" />
              <p className="text-slate-400 font-space italic">
                "Hello. I am your specialized neural architect for {state.skillName}.<br/>How shall we accelerate your mastery today?"
              </p>
            </div>
          )}

          {state.chatHistory.map((msg, idx) => (
            <div 
              key={idx} 
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}
            >
              <div className={`max-w-[80%] p-5 rounded-2xl font-medium leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-sky-500 text-white shadow-lg shadow-sky-950/20' 
                  : 'bg-slate-900/80 border border-white/5 text-slate-200'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start">
              <div className="p-4 bg-slate-900/50 rounded-2xl flex gap-1 items-center">
                <div className="w-1 h-1 bg-sky-400 rounded-full animate-bounce"></div>
                <div className="w-1 h-1 bg-sky-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1 h-1 bg-sky-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleSend} className="p-6 bg-slate-950/50 border-t border-white/5 flex gap-4">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Query the mentor..."
            className="flex-1 bg-slate-900/50 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none focus:ring-2 focus:ring-sky-500/50 transition-all font-space"
          />
          <button 
            disabled={!input.trim() || isTyping}
            className="w-14 h-14 rounded-2xl bg-sky-500 flex items-center justify-center text-white hover:bg-sky-400 transition-all shadow-lg shadow-sky-950/20 disabled:opacity-50"
          >
            <ICONS.ArrowRight className="w-6 h-6" />
          </button>
        </form>
      </div>
    </div>
  );
};

