          </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 z-10 p-6 max-w-7xl mx-auto w-full">
        {loading ? (
          <div className="flex flex-col items-center justify-center h-full gap-6">
            <div className="relative">
              <div className="w-24 h-24 border-4 border-sky-400/20 border-t-sky-400 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <ICONS.Brain className="w-8 h-8 text-sky-400 animate-pulse" />
              </div>
            </div>
            <p className="text-xl font-space text-slate-300 animate-pulse-soft">{loadingMsg}</p>
          </div>
        ) : (
          <>
            {state.currentStep === 'discovery' && (
              <DiscoveryPage onStart={handleStartDiscovery} />
            )}
            {state.currentStep === 'assessment' && (
              <AssessmentPage 
                questions={state.assessmentQuestions} 
                onComplete={handleAssessmentComplete}
                skill={state.skillName}
              />
            )}
            {state.currentStep === 'result' && (
              <ResultPage 
                results={state.assessmentResults} 
                initialLevel={state.initialLevel}
                verifiedLevel={state.verifiedLevel!}
                onProceed={handleGenerateRoadmap}
              />
            )}
            {state.currentStep === 'roadmap' && (
              <RoadmapPage 
                roadmap={state.roadmap!} 
                activeDay={state.activeDay}
                onSelectDay={(day) => setState(prev => ({ ...prev, activeDay: day, currentStep: 'session' }))}
              />
            )}
            {state.currentStep === 'session' && (
              <SessionPage 
                day={state.roadmap?.days.find(d => d.day === state.activeDay)}
                onComplete={() => navigateTo('dashboard')}
                onConsultMentor={() => navigateTo('mentor')}
              />
            )}
            {state.currentStep === 'dashboard' && (
              <DashboardPage 
                state={state} 
                onStartSkill={() => navigateTo('discovery')} 
                onContinueSkill={() => navigateTo('roadmap')}
              />
            )}
            {state.currentStep === 'mentor' && (
              <MentorPage state={state} updateChatHistory={updateChatHistory} />
            )}
            {state.currentStep === 'arena' && (
              <ArenaPage state={state} onSelectDay={(day) => navigateTo('session', { activeDay: day })} />
            )}
          </>
        )}
      </main>

      <footer className="z-10 py-6 border-t border-white/5 text-center text-slate-500 text-sm">
        <p>© 2024 Nexus Academy. Futuristic AI Learning.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { AppState, ChatMessage } from '../types';
import { ICONS } from '../constants';
import { geminiService } from '../services/gemini';
import { Chat, GenerateContentResponse } from '@google/genai';

interface MentorPageProps {
  state: AppState;
  updateChatHistory: (messages: ChatMessage[]) => void;
}

const MentorPage: React.FC<MentorPageProps> = ({ state, updateChatHistory }) => {
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const chatRef = useRef<Chat | null>(null);

  useEffect(() => {
    if (!chatRef.current) {
      chatRef.current = geminiService.createMentorChat(state.skillName, state.verifiedLevel || state.initialLevel, state.selectedGoal);
    }
  }, [state]);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [state.chatHistory]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMessage: ChatMessage = { role: 'user', text: input };
    const updatedHistory = [...state.chatHistory, userMessage];
    updateChatHistory(updatedHistory);
    setInput('');
    setIsTyping(true);

    try {
      if (chatRef.current) {
        const stream = await chatRef.current.sendMessageStream({ message: input });
        let modelText = '';

        // Optimistically add empty model message
        updateChatHistory([...updatedHistory, { role: 'model', text: '' }]);

        for await (const chunk of stream) {
          const c = chunk as GenerateContentResponse;
          modelText += c.text;
          const currentHistory = [...updatedHistory, { role: 'model', text: modelText }];
          updateChatHistory(currentHistory);
        }
      }
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = { role: 'model', text: "Apologies, neural sync lost. Please retry link." };
      updateChatHistory([...updatedHistory, errorMsg]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[75vh] animate-in fade-in duration-700">
      <div className="flex items-center justify-between mb-6 px-4">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-2xl bg-amber-500/10 border border-amber-500/20 flex items-center justify-center">
            <ICONS.Brain className="w-6 h-6 text-amber-500" />
          </div>
          <div>
            <h2 className="text-2xl font-space font-bold">{state.skillName} Specialist</h2>
            <p className="text-xs text-slate-500 font-bold uppercase tracking-widest flex items-center gap-1">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
              Neural Expert Locked & Loaded
            </p>
          </div>
        </div>
      </div>

      <div className="flex-1 glass rounded-[2.5rem] overflow-hidden flex flex-col relative">
        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto p-8 space-y-6 scrollbar-hide"
        >
          {state.chatHistory.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-4 opacity-50">
              <ICONS.Message className="w-12 h-12 text-slate-600" />
              <p className="text-slate-400 font-space italic">
                "Initiating expertise in {state.skillName}. <br/>Whether it's architectural scaling or specific syntax, I am here to optimize your learning path."
              </p>
            </div>
          )}

          {state.chatHistory.map((msg, idx) => (
            <div 
              key={idx} 
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}
            >
              <div className={`max-w-[85%] p-5 rounded-2xl font-medium leading-relaxed prose prose-invert prose-sm ${
                msg.role === 'user' 
                  ? 'bg-sky-500 text-white shadow-lg shadow-sky-950/20 rounded-tr-none' 
                  : 'bg-slate-900/80 border border-white/5 text-slate-200 rounded-tl-none'
              }`}>
                {msg.text.split('\n').map((line, i) => (
                  <p key={i} className="mb-2 last:mb-0">{line}</p>
                ))}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start">
              <div className="p-4 bg-slate-900/50 rounded-2xl flex gap-1 items-center">
                <div className="w-1 h-1 bg-sky-400 rounded-full animate-bounce"></div>
                <div className="w-1 h-1 bg-sky-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1 h-1 bg-sky-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleSend} className="p-6 bg-slate-950/50 border-t border-white/5 flex gap-4">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={`Query about ${state.skillName}...`}
            className="flex-1 bg-slate-900/50 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none focus:ring-2 focus:ring-sky-500/50 transition-all font-space"
          />
          <button 
            disabled={!input.trim() || isTyping}
            className="w-14 h-14 rounded-2xl bg-sky-500 flex items-center justify-center text-white hover:bg-sky-400 transition-all shadow-lg shadow-sky-950/20 disabled:opacity-50"
          >
            <ICONS.ArrowRight className="w-6 h-6" />
          </button>
        </form>
      </div>
    </div>
  );
};

