import React, { useState, useEffect, useCallback } from 'react';
import { AppState, SkillLevel, AssessmentQuestion, LearningRoadmap, ChatMessage, Enrollment } from './types';
import { GOALS, ICONS } from './constants';
import { geminiService } from './services/gemini';

// Components
import DiscoveryPage from './pages/DiscoveryPage';
import AssessmentPage from './pages/AssessmentPage';
import ResultPage from './pages/ResultPage';
import RoadmapPage from './pages/RoadmapPage';
import DashboardPage from './pages/DashboardPage';
import SessionPage from './pages/SessionPage';
import MentorPage from './pages/MentorPage';
import ArenaPage from './pages/ArenaPage';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    currentStep: 'dashboard',
    skillName: '',
    selectedGoal: GOALS[0].id,
    initialLevel: SkillLevel.BEGINNER,
    verifiedLevel: null,
    assessmentQuestions: [],
    assessmentResults: [],
    enrollments: [],
    activeEnrollmentIndex: null,
    streak: 3
  });

  const [loading, setLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState('');

  const activeEnrollment = state.activeEnrollmentIndex !== null ? state.enrollments[state.activeEnrollmentIndex] : null;

  const handleStartDiscovery = async (skill: string, goal: string, level: SkillLevel) => {
    setState(prev => ({
      ...prev,
      skillName: skill,
      selectedGoal: goal,
      initialLevel: level,
    }));

    if (level === SkillLevel.NO_IDEA) {
      await generateRoadmapInternal(skill, level, goal);
    } else {
      setLoading(true);
      setLoadingMsg('Architecting your assessment...');
      try {
        const questions = await geminiService.generateAssessment(skill, level);
        setState(prev => ({
          ...prev,
          assessmentQuestions: questions,
          currentStep: 'assessment',
        }));
      } catch (error) {
        console.error(error);
        alert('Failed to generate assessment. Please try again.');
      } finally {
        setLoading(false);
      }
    }
  };

  const handleAssessmentComplete = (results: { questionId: string; selectedIndex: number; isCorrect: boolean }[]) => {
    const correctCount = results.filter(r => r.isCorrect).length;
    let verified = state.initialLevel;

    if (correctCount < 3) {
      const levels = [
        SkillLevel.BEGINNER,
        SkillLevel.INTERMEDIATE,
        SkillLevel.ADVANCED,
        SkillLevel.EXPERT
      ];
      const currentIndex = levels.indexOf(state.initialLevel);
      if (currentIndex > 0) {
        verified = levels[currentIndex - 1];
      } else {
        verified = SkillLevel.NO_IDEA;
      }
    }

    setState(prev => ({
      ...prev,
      assessmentResults: results,
      verifiedLevel: verified,
      currentStep: 'result'
    }));
  };

  const generateRoadmapInternal = async (skill: string, level: SkillLevel, goal: string) => {
    setLoading(true);
    setLoadingMsg('Personalizing your zero-assumption path...');
    try {
      const duration = goal === 'interview' ? 14 : 30;
      const roadmap = await geminiService.generateRoadmap(
        skill,
        level,
        duration,
        goal
      );

      const newEnrollment: Enrollment = {
        roadmap,
        activeDay: 1,
        confidenceScore: 0,
        chatHistory: []
      };

      setState(prev => ({
        ...prev,
        enrollments: [...prev.enrollments, newEnrollment],
        activeEnrollmentIndex: prev.enrollments.length,
        currentStep: 'roadmap'
      }));
    } catch (error) {
      console.error(error);
      alert('Failed to generate roadmap.');
    } finally {
      setLoading(false);
    }
  };

  const handleGenerateRoadmap = async () => {
    await generateRoadmapInternal(state.skillName, state.verifiedLevel || state.initialLevel, state.selectedGoal);
  };

  const navigateTo = (step: AppState['currentStep'], payload?: Partial<AppState>) => {
    setState(prev => ({ ...prev, currentStep: step, ...payload }));
  };

  const updateChatHistory = (history: ChatMessage[]) => {
    if (state.activeEnrollmentIndex === null) return;
    setState(prev => {
      const newEnrollments = [...prev.enrollments];
      newEnrollments[prev.activeEnrollmentIndex!] = {
        ...newEnrollments[prev.activeEnrollmentIndex!],
        chatHistory: history
      };
      return { ...prev, enrollments: newEnrollments };
    });
  };

  const handleSwitchSkill = (index: number) => {
    setState(prev => ({
      ...prev,
      activeEnrollmentIndex: index,
      currentStep: 'roadmap'
    }));
  };

  const handleUpdateActiveDay = (day: number) => {
    if (state.activeEnrollmentIndex === null) return;
    setState(prev => {
      const newEnrollments = [...prev.enrollments];
      const enrollment = newEnrollments[prev.activeEnrollmentIndex!];

      // Prevent exceeding duration
      const targetDay = Math.min(day, enrollment.roadmap.duration);

      newEnrollments[prev.activeEnrollmentIndex!] = {
        ...enrollment,
        activeDay: targetDay
      };
      return { ...prev, enrollments: newEnrollments, currentStep: 'session' };
    });
  };

  return (
    <div className="min-h-screen relative overflow-hidden flex flex-col">
      {/* Background Decor */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-sky-500/10 blur-[120px] rounded-full"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-500/10 blur-[120px] rounded-full"></div>

      {/* Navigation Header */}
      <nav className="z-50 px-6 py-4 flex justify-between items-center border-b border-white/5 bg-slate-950/50 backdrop-blur-md sticky top-0">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => navigateTo('dashboard')}>
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-sky-400 to-purple-600 flex items-center justify-center neon-blue">
            <ICONS.Brain className="w-6 h-6 text-white" />
          </div>
          <span className="font-space text-xl font-bold tracking-tight">NEXUS<span className="text-sky-400">.</span>ACADEMY</span>
        </div>

        <div className="flex gap-4 items-center">
            {activeEnrollment && (
              <div className="hidden lg:flex gap-2">
                <button 
                  onClick={() => navigateTo('roadmap')}
                  className={`px-4 py-2 rounded-lg transition-all text-xs font-bold uppercase tracking-widest ${state.currentStep === 'roadmap' ? 'bg-sky-500/10 text-sky-400' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  Roadmap
                </button>
                <button 
                  onClick={() => navigateTo('arena')}
                  className={`px-4 py-2 rounded-lg transition-all text-xs font-bold uppercase tracking-widest ${state.currentStep === 'arena' ? 'bg-purple-500/10 text-purple-400' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  Arena
                </button>
                <button 
                  onClick={() => navigateTo('mentor')}
                  className={`px-4 py-2 rounded-lg transition-all text-xs font-bold uppercase tracking-widest ${state.currentStep === 'mentor' ? 'bg-amber-500/10 text-amber-400' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  Mentor
                </button>
              </div>
            )}

            <button 
              onClick={() => navigateTo('dashboard')}
              className={`px-4 py-2 rounded-lg glass transition-all ${state.currentStep === 'dashboard' ? 'bg-white/10 text-white' : 'hover:bg-white/10'}`}
            >
              Dashboard
            </button>
          </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 z-10 p-6 max-w-7xl mx-auto w-full">
        {loading ? (
          <div className="flex flex-col items-center justify-center h-full gap-6">
            <div className="relative">
              <div className="w-24 h-24 border-4 border-sky-400/20 border-t-sky-400 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <ICONS.Brain className="w-8 h-8 text-sky-400 animate-pulse" />
              </div>
            </div>
            <p className="text-xl font-space text-slate-300 animate-pulse-soft">{loadingMsg}</p>
          </div>
        ) : (
          <>
            {state.currentStep === 'discovery' && (
              <DiscoveryPage onStart={handleStartDiscovery} />
            )}
            {state.currentStep === 'assessment' && (
              <AssessmentPage 
                questions={state.assessmentQuestions} 
                onComplete={handleAssessmentComplete}
                skill={state.skillName}
              />
            )}
            {state.currentStep === 'result' && (
              <ResultPage 
                results={state.assessmentResults} 
                initialLevel={state.initialLevel}
                verifiedLevel={state.verifiedLevel!}
                onProceed={handleGenerateRoadmap}
              />
            )}
            {state.currentStep === 'roadmap' && activeEnrollment && (
              <RoadmapPage 
                roadmap={activeEnrollment.roadmap} 
                activeDay={activeEnrollment.activeDay}
                onSelectDay={handleUpdateActiveDay}
              />
            )}
            {state.currentStep === 'session' && activeEnrollment && (
              <SessionPage 
                day={activeEnrollment.roadmap.days.find(d => d.day === activeEnrollment.activeDay)}
                totalDays={activeEnrollment.roadmap.duration}
                onComplete={() => navigateTo('dashboard')}
                onNextDay={() => handleUpdateActiveDay(activeEnrollment.activeDay + 1)}
                onConsultMentor={() => navigateTo('mentor')}
              />
            )}
            {state.currentStep === 'dashboard' && (
              <DashboardPage 
                state={state} 
                onStartSkill={() => navigateTo('discovery')} 
                onSwitchSkill={handleSwitchSkill}
              />
            )}
            {state.currentStep === 'mentor' && activeEnrollment && (
              <MentorPage 
                skillName={activeEnrollment.roadmap.skill}
                level={activeEnrollment.roadmap.level}
                goal={activeEnrollment.roadmap.goal}
                chatHistory={activeEnrollment.chatHistory}
                updateChatHistory={updateChatHistory} 
              />
            )}
            {state.currentStep === 'arena' && activeEnrollment && (
              <ArenaPage 
                roadmap={activeEnrollment.roadmap}
                activeDay={activeEnrollment.activeDay}
                onSelectDay={handleUpdateActiveDay} 
              />
            )}
          </>
        )}
      </main>

      <footer className="z-10 py-6 border-t border-white/5 text-center text-slate-500 text-sm">
        <p>© 2024 Nexus Academy. Futuristic AI Learning.</p>
      </footer>
    </div>
  );
};

export default App;

export enum SkillLevel {
