  BEGINNER = 'Beginner',
  INTERMEDIATE = 'Intermediate',
  ADVANCED = 'Advanced',
  EXPERT = 'Expert'
}

export interface SkillGoal {
  id: string;
  label: string;
}

export interface AssessmentQuestion {
  id: string;
  question: string;
  options: string[];
  correctIndex: number;
  explanation: string;
  category: string;
}

export interface RoadmapDay {
  day: number;
  concept: string;
  relevance: string;
  handsOnTask: string;
  estimatedTime: string;
  quizQuestions: {
    question: string;
    options: string[];
    answer: string;
  }[];
  challenge: string;
}

export interface LearningRoadmap {
  skill: string;
  level: SkillLevel;
  duration: number;
  goal: string;
  days: RoadmapDay[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export interface Enrollment {
  roadmap: LearningRoadmap;
  activeDay: number;
  confidenceScore: number;
  chatHistory: ChatMessage[];
}

export interface User {
  id: string;
  username: string;
  isGuest: boolean;
  avatar?: string;
}

export interface AppState {
  currentStep: 'auth' | 'discovery' | 'assessment' | 'result' | 'roadmap' | 'dashboard' | 'session' | 'mentor' | 'arena';
  user: User | null;
  // Discovery Flow State
  skillName: string;
  selectedGoal: string;
  initialLevel: SkillLevel;
  verifiedLevel: SkillLevel | null;
  assessmentQuestions: AssessmentQuestion[];
  assessmentResults: { questionId: string; selectedIndex: number; isCorrect: boolean }[];

  // Persistence State
  enrollments: Enrollment[];
  activeEnrollmentIndex: number | null;
  streak: number;
}

import { AppState, User } from '../types';

const STORAGE_KEY = 'nexus_academy_state';
const LOG_KEY = 'nexus_academy_logs';

export const storageService = {
  saveState: (state: AppState) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  },

  loadState: (): Partial<AppState> | null => {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : null;
  },

  clearState: () => {
    localStorage.removeItem(STORAGE_KEY);
  },

  logEvent: (userId: string, eventType: string, data: any = {}) => {
    const logs = JSON.parse(localStorage.getItem(LOG_KEY) || '[]');
    const newLog = {
      userId,
      eventType,
      data,
      timestamp: new Date().toISOString()
    };
    logs.push(newLog);
    localStorage.setItem(LOG_KEY, JSON.stringify(logs.slice(-100))); // Keep last 100
    console.debug(`[NEXUS LOG]: ${eventType}`, newLog);
  }
};

