const DEFAULT_STATE: AppState = {
  currentStep: 'auth',
  user: null,
  skillName: '',
  selectedGoal: GOALS[0].id,
  initialLevel: SkillLevel.BEGINNER,
  verifiedLevel: null,
  assessmentQuestions: [],
  assessmentResults: [],
  enrollments: [],
  activeEnrollmentIndex: null,
  streak: 0
};

