  const [state, setState] = useState<AppState>(() => {
    const saved = storageService.loadState();
    // Use spread to ensure any missing properties in local storage don't cause undefined errors
    return { ...DEFAULT_STATE, ...saved } as AppState;
  });

  const [loading, setLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState('');

  // Auto-save on state changes
  useEffect(() => {
    storageService.saveState(state);
  }, [state]);

  const activeEnrollment = state.activeEnrollmentIndex !== null ? state.enrollments[state.activeEnrollmentIndex] : null;

